          ctx.save();
          const gradient = ctx.createLinearGradient(x, y, x, y + height);
          gradient.addColorStop(0, `rgba(${color2.r}, ${color2.g}, ${color2.b}, 0.9)`);
          gradient.addColorStop(1, `rgba(${Math.max(0, color2.r - 30)}, ${Math.max(0, color2.g - 30)}, ${Math.max(0, color2.b - 30)}, 0.9)`);
          ctx.fillStyle = gradient;
          ctx.fillRect(x, y, width, height);
