        bodyStyle: this.parseTextStyleElement(txStylesElement.querySelector("bodyStyle, p\\:bodyStyle")),
        otherStyle: this.parseTextStyleElement(txStylesElement.querySelector("otherStyle, p\\:otherStyle"))
