    layout.showMasterSp = layoutElement.getAttribute("showMasterSp") !== "false";
    layout.showMasterPhAnim = layoutElement.getAttribute("showMasterPhAnim") === "true";
    layout.userDrawn = layoutElement.getAttribute("userDrawn") !== "false";
